  ('retired-7fec267e-moex-00019', 'retired-7fec267e', 'retired-7fec267e-moex-114-3d2b73b6', 'sub-retired-7fec267e-04', NULL, 'single_choice', '有關禁止法律溯及既往原則與過渡條款，下列敘述何者正確？', '["限制基本權利之法律，若適用於該法律施行前已終結之事件，乃憲法所絕對不許", "基於禁止法律溯及既往原則，對人民有利之法律，不得適用於該法律施行前已終結之事件", "基於禁止法律溯及既往原則，法律不得適用於施行前已發生，施行後繼續存在之法律關係", "立法者制定新法，若應設卻未設過渡條款適度排除新法之適用範圍，此一法律漏洞仍有由司法機關 補充之可能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00020', 'retired-7fec267e', 'retired-7fec267e-moex-114-3d2b73b6', 'sub-retired-7fec267e-04', NULL, 'single_choice', '依據憲法增修條文規定，有關基本國策，國家對於公營金融機構之管理，應本下列何種原則？', '["社會平等", "企業化經營", "組織現代化", "提升競爭力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00021', 'retired-7fec267e', 'retired-7fec267e-moex-114-3d2b73b6', 'sub-retired-7fec267e-04', NULL, 'single_choice', '政黨為人民之政治性結社團體，有關政黨與結社自由，下列敘述何者錯誤？', '["基於結社自由，人民得自由選擇加入或退出特定政黨", "政黨財產之使用、收益及處分，受財產權及結社自由之憲法保障", "政黨就其存續、內部之組織與運作以及對外活動等，不受國家恣意之干預", "政黨於民主政治運作有其重要性與必要性，故國家不得以任何理由解散政黨"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00022', 'retired-7fec267e', 'retired-7fec267e-moex-114-3d2b73b6', 'sub-retired-7fec267e-04', NULL, 'single_choice', '所得稅法將軍人、國小教師原本免繳所得稅之規定，改為有所得即應繳稅，屬於憲法平等原則對何國 家機關的拘束？', '["對監察院之拘束", "對司法院之拘束", "對行政院之拘束", "對立法院之拘束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00023', 'retired-7fec267e', 'retired-7fec267e-moex-114-3d2b73b6', 'sub-retired-7fec267e-04', NULL, 'single_choice', '下列何者與憲法第15條保障之工作權無關？', '["老年年金制度", "限制醫師藥品調劑權", "勞資爭議處理機制", "對童工的相關保護規範"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00024', 'retired-7fec267e', 'retired-7fec267e-moex-114-3d2b73b6', 'sub-retired-7fec267e-04', NULL, 'single_choice', '依司法院釋字第490號解釋，有關「中華民國男子依法皆有服兵役之義務」規定，下列敘述何者 錯誤？', '["基於憲法平等原則的要求，應將女子排除於兵役義務之外", "人民履行兵役義務的方式，應由立法者決定", "人民有服兵役之義務，此為憲法明文規定", "關於服兵役之重要事項，立法者應斟酌國家安全之需要，予以規定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
